            "loss.py": "\"\"\"Loss function for this candidate.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef loss_fn(model: nn.Module, pred: torch.Tensor, target: torch.Tensor) -> torch.Tensor:\n    if pred.ndim == 3:\n        vocab = pred.shape[-1]\n        return torch.nn.functional.cross_entropy(pred.reshape(-1, vocab), target.reshape(-1))\n    return torch.nn.functional.cross_entropy(pred, target.reshape(-1))\n",
            "model.py": "\"\"\"Causal transformer language model.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\nclass Model(nn.Module):\n    def __init__(self) -> None:\n        super().__init__()\n        self.context_length = 16\n        self.token_embed = nn.Embedding(32, 64)\n        self.pos_embed = nn.Embedding(16, 64)\n        layer = nn.TransformerEncoderLayer(\n            d_model=64,\n            nhead=2,\n            dim_feedforward=256,\n            dropout=0.0,\n            batch_first=True,\n            activation=\"gelu\",\n        )\n        self.encoder = nn.TransformerEncoder(layer, num_layers=2)\n        self.head = nn.Linear(64, 32)\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        b, seq_len = x.shape\n        positions = torch.arange(seq_len, device=x.device).unsqueeze(0).expand(b, -1)\n        h = self.token_embed(x) + self.pos_embed(positions)\n        mask = torch.triu(torch.ones(seq_len, seq_len, device=x.device), diagonal=1).bool()\n        h = self.encoder(h, mask=mask)\n        return self.head(h)\n",
            "optimizer.py": "\"\"\"Optimizer factory for this candidate.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef build_optimizer(model: nn.Module) -> torch.optim.Optimizer:\n    params = model.parameters()\n    return torch.optim.SGD(params, lr=0.01, momentum=0.9, weight_decay=0.001)\n",
            "train.py": "\"\"\"Training loop for this candidate — executed by the ground-truth runner.\"\"\"\nfrom __future__ import annotations\n\nimport math\n\nimport torch\nimport torch.nn.functional as F\n\nfrom loss import loss_fn\nfrom model import Model\nfrom optimizer import build_optimizer\n\n\ndef _test_ce(model: torch.nn.Module, test_x: torch.Tensor, test_y: torch.Tensor) -> float:\n    model.eval()\n    with torch.no_grad():\n        pred = model(test_x)\n        if pred.ndim == 3:\n            vocab = pred.shape[-1]\n            loss = F.cross_entropy(pred.reshape(-1, vocab), test_y.reshape(-1))\n        else:\n            loss = F.cross_entropy(pred, test_y.reshape(-1))\n        return float(loss.item())\n\n\ndef train_and_eval(\n    train_x: torch.Tensor,\n    train_y: torch.Tensor,\n    test_x: torch.Tensor,\n    test_y: torch.Tensor,\n    *,\n    steps: int,\n    batch_size: int,\n    seed: int = 0,\n    fail_threshold: float = float(\"inf\"),\n) -> dict:\n    torch.manual_seed(seed)\n    model = Model()\n    optimizer = build_optimizer(model)\n    n = train_x.shape[0]\n    step_metrics: list[float] = []\n    eval_samples: list[int] = []\n    failed = False\n\n    for step in range(1, steps + 1):\n        model.train()\n        idx = torch.randint(0, n, (batch_size,))\n        pred = model(train_x[idx])\n        loss = loss_fn(model, pred, train_y[idx])\n        if not torch.isfinite(loss):\n            failed = True\n            break\n        optimizer.zero_grad()\n        loss.backward()\n        optimizer.step()\n\n        metric = _test_ce(model, test_x, test_y)\n        if not math.isfinite(metric):\n            failed = True\n            break\n        eval_samples.append(step * batch_size)\n        step_metrics.append(metric)\n\n    final_metric = step_metrics[-1] if step_metrics else float(\"inf\")\n    if final_metric > fail_threshold:\n        failed = True\n\n    return {\n        \"failed\": failed,\n        \"final_test_ce\": final_metric,\n        \"eval_samples\": eval_samples,\n        \"step_metrics\": step_metrics,\n    }\n",
            "summary.json": "{\n  \"schema_version\": \"1.0\",\n  \"candidate_id\": \"c_91d842\",\n  \"selection_metric\": \"test_ce\",\n  \"execution\": \"candidate_py_files\",\n  \"n_seeds\": 10,\n  \"base_seed\": 0,\n  \"failed_seeds\": 0,\n  \"excluded\": false,\n  \"mean_test_ce\": 3.3380643844604494,\n  \"std_test_ce\": 0.007795232410368096,\n  \"seed_results\": [\n    {\n      \"seed\": 0,\n      \"failed\": false,\n      \"final_test_ce\": 3.332955837249756\n    },\n    {\n      \"seed\": 1,\n      \"failed\": false,\n      \"final_test_ce\": 3.349968910217285\n    },\n    {\n      \"seed\": 2,\n      \"failed\": false,\n      \"final_test_ce\": 3.341679573059082\n    },\n    {\n      \"seed\": 3,\n      \"failed\": false,\n      \"final_test_ce\": 3.332737684249878\n    },\n    {\n      \"seed\": 4,\n      \"failed\": false,\n      \"final_test_ce\": 3.3453903198242188\n    },\n    {\n      \"seed\": 5,\n      \"failed\": false,\n      \"final_test_ce\": 3.3373453617095947\n    },\n    {\n      \"seed\": 6,\n      \"failed\": false,\n      \"final_test_ce\": 3.330796718597412\n    },\n    {\n      \"seed\": 7,\n      \"failed\": false,\n      \"final_test_ce\": 3.3386542797088623\n    },\n    {\n      \"seed\": 8,\n      \"failed\": false,\n      \"final_test_ce\": 3.3473575115203857\n    },\n    {\n      \"seed\": 9,\n      \"failed\": false,\n      \"final_test_ce\": 3.3237576484680176\n    }\n  ],\n  \"environment\": {\n    \"python\": \"3.12.7 | packaged by Anaconda, Inc. | (main, Oct  4 2024, 08:22:19) [Clang 14.0.6 ]\",\n    \"platform\": \"macOS-15.3.1-arm64-arm-64bit\",\n    \"torch\": \"2.12.1\",\n    \"device\": \"cpu\",\n    \"git_commit\": \"20f0b6c5c240dd9bf99334e1cda8714e3ddf32df\"\n  }\n}"
