            "train.py": "\"\"\"Training loop for this candidate — executed by the ground-truth runner.\"\"\"\nfrom __future__ import annotations\n\nimport math\n\nimport torch\n\nfrom loss import loss_fn\nfrom model import Model\nfrom optimizer import build_optimizer\n\n\ndef _test_mse(model: torch.nn.Module, test_x: torch.Tensor, test_y: torch.Tensor) -> float:\n    model.eval()\n    with torch.no_grad():\n        pred = model(test_x)\n        return float(torch.mean((pred - test_y) ** 2).item())\n\n\ndef train_and_eval(\n    train_x: torch.Tensor,\n    train_y: torch.Tensor,\n    test_x: torch.Tensor,\n    test_y: torch.Tensor,\n    *,\n    steps: int,\n    batch_size: int,\n    seed: int = 0,\n    fail_threshold: float = float(\"inf\"),\n) -> dict:\n    torch.manual_seed(seed)\n    model = Model()\n    optimizer = build_optimizer(model)\n    n = train_x.shape[0]\n    step_metrics: list[float] = []\n    eval_samples: list[int] = []\n    failed = False\n\n    for step in range(1, steps + 1):\n        model.train()\n        idx = torch.randint(0, n, (batch_size,))\n        pred = model(train_x[idx])\n        loss = loss_fn(model, pred, train_y[idx])\n        if not torch.isfinite(loss):\n            failed = True\n            break\n        optimizer.zero_grad()\n        loss.backward()\n        optimizer.step()\n\n        metric = _test_mse(model, test_x, test_y)\n        if not math.isfinite(metric):\n            failed = True\n            break\n        eval_samples.append(step * batch_size)\n        step_metrics.append(metric)\n\n    final_metric = step_metrics[-1] if step_metrics else float(\"inf\")\n    if final_metric > fail_threshold:\n        failed = True\n\n    return {\n        \"failed\": failed,\n        \"final_test_mse\": final_metric,\n        \"eval_samples\": eval_samples,\n        \"step_metrics\": step_metrics,\n    }\n\n\ndef train(\n    train_x: torch.Tensor,\n    train_y: torch.Tensor,\n    *,\n    steps: int,\n    batch_size: int,\n    seed: int = 0,\n) -> None:\n    \"\"\"Minimal training entrypoint (no evaluation).\"\"\"\n    train_and_eval(\n        train_x,\n        train_y,\n        test_x=train_x,\n        test_y=train_y,\n        steps=steps,\n        batch_size=batch_size,\n        seed=seed,\n        fail_threshold=float(\"inf\"),\n    )\n",
