            "loss.py": "\"\"\"Loss function for this candidate.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef loss_fn(model: nn.Module, pred: torch.Tensor, target: torch.Tensor) -> torch.Tensor:\n    base = torch.mean((pred - target) ** 2)\n    l1 = torch.mean(torch.stack([torch.mean(torch.abs(p)) for p in model.parameters()]))\n    return base + 0.001 * l1\n",
            "model.py": "\"\"\"MLP model — matches candidate_spec model section.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef _activation(name: str) -> nn.Module:\n    mapping = {\n        \"relu\": nn.ReLU(),\n        \"leaky_relu\": nn.LeakyReLU(0.1),\n        \"gelu\": nn.GELU(),\n        \"silu\": nn.SiLU(),\n    }\n    return mapping[name]\n\n\nclass MLPBlock(nn.Module):\n    def __init__(self, width: int, activation: str, use_layer_norm: bool, use_residual: bool) -> None:\n        super().__init__()\n        self.use_residual = use_residual\n        self.norm = nn.LayerNorm(width) if use_layer_norm else None\n        self.linear = nn.Linear(width, width)\n        self.act = _activation(activation)\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        h = x\n        if self.norm is not None:\n            h = self.norm(h)\n        h = self.linear(h)\n        h = self.act(h)\n        if self.use_residual:\n            h = h + x\n        return h\n\n\nclass Model(nn.Module):\n    def __init__(self) -> None:\n        super().__init__()\n        self.net = nn.Sequential(\n            nn.Linear(1, 256),\n        MLPBlock(width=256, activation='leaky_relu', use_layer_norm=False, use_residual=False),\n        MLPBlock(width=256, activation='leaky_relu', use_layer_norm=True, use_residual=False),\n            nn.Linear(256, 1),\n        )\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        return self.net(x)\n",
