            "candidate_spec.json": "{\n  \"schema_version\": \"1.0\",\n  \"dataset_id\": \"sym_62678b\",\n  \"family\": \"univariate_regression\",\n  \"budget\": {\n    \"training_steps\": 64,\n    \"batch_size\": 32,\n    \"total_samples_seen\": 2048\n  },\n  \"model\": {\n    \"type\": \"mlp\",\n    \"depth\": 5,\n    \"width\": 256,\n    \"residual\": false,\n    \"layer_norm\": [\n      true,\n      false,\n      false,\n      true,\n      true\n    ],\n    \"activations\": [\n      \"silu\",\n      \"leaky_relu\",\n      \"silu\",\n      \"gelu\",\n      \"silu\"\n    ],\n    \"input_dim\": 1\n  },\n  \"optimizer\": {\n    \"type\": \"Adagrad\",\n    \"lr\": 0.001,\n    \"weight_decay\": 1e-05\n  },\n  \"loss\": {\n    \"loss_id\": \"mse\"\n  },\n  \"files\": {\n    \"model\": \"model.py\",\n    \"train\": \"train.py\",\n    \"loss\": \"loss.py\",\n    \"optimizer\": \"optimizer.py\"\n  },\n  \"candidate_id\": \"c_701404\"\n}",
            "loss.py": "\"\"\"Loss function for this candidate.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef loss_fn(model: nn.Module, pred: torch.Tensor, target: torch.Tensor) -> torch.Tensor:\n    return torch.mean((pred - target) ** 2)\n",
            "model.py": "\"\"\"MLP model — matches candidate_spec model section.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef _activation(name: str) -> nn.Module:\n    mapping = {\n        \"relu\": nn.ReLU(),\n        \"leaky_relu\": nn.LeakyReLU(0.1),\n        \"gelu\": nn.GELU(),\n        \"silu\": nn.SiLU(),\n    }\n    return mapping[name]\n\n\nclass MLPBlock(nn.Module):\n    def __init__(self, width: int, activation: str, use_layer_norm: bool, use_residual: bool) -> None:\n        super().__init__()\n        self.use_residual = use_residual\n        self.norm = nn.LayerNorm(width) if use_layer_norm else None\n        self.linear = nn.Linear(width, width)\n        self.act = _activation(activation)\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        h = x\n        if self.norm is not None:\n            h = self.norm(h)\n        h = self.linear(h)\n        h = self.act(h)\n        if self.use_residual:\n            h = h + x\n        return h\n\n\nclass Model(nn.Module):\n    def __init__(self) -> None:\n        super().__init__()\n        self.net = nn.Sequential(\n            nn.Linear(1, 256),\n        MLPBlock(width=256, activation='silu', use_layer_norm=True, use_residual=False),\n        MLPBlock(width=256, activation='leaky_relu', use_layer_norm=False, use_residual=False),\n        MLPBlock(width=256, activation='silu', use_layer_norm=False, use_residual=False),\n        MLPBlock(width=256, activation='gelu', use_layer_norm=True, use_residual=False),\n        MLPBlock(width=256, activation='silu', use_layer_norm=True, use_residual=False),\n            nn.Linear(256, 1),\n        )\n\n    def forward(self, x: torch.Tensor) -> torch.Tensor:\n        return self.net(x)\n",
            "optimizer.py": "\"\"\"Optimizer factory for this candidate.\"\"\"\nfrom __future__ import annotations\n\nimport torch\nimport torch.nn as nn\n\n\ndef build_optimizer(model: nn.Module) -> torch.optim.Optimizer:\n    params = model.parameters()\n    return torch.optim.Adagrad(params, lr=0.001, weight_decay=1e-05)\n",
            "train.py": "\"\"\"Training loop for this candidate — executed by the ground-truth runner.\"\"\"\nfrom __future__ import annotations\n\nimport math\n\nimport torch\n\nfrom loss import loss_fn\nfrom model import Model\nfrom optimizer import build_optimizer\n\n\ndef _test_mse(model: torch.nn.Module, test_x: torch.Tensor, test_y: torch.Tensor) -> float:\n    model.eval()\n    with torch.no_grad():\n        pred = model(test_x)\n        return float(torch.mean((pred - test_y) ** 2).item())\n\n\ndef train_and_eval(\n    train_x: torch.Tensor,\n    train_y: torch.Tensor,\n    test_x: torch.Tensor,\n    test_y: torch.Tensor,\n    *,\n    steps: int,\n    batch_size: int,\n    seed: int = 0,\n    fail_threshold: float = float(\"inf\"),\n) -> dict:\n    torch.manual_seed(seed)\n    model = Model()\n    optimizer = build_optimizer(model)\n    n = train_x.shape[0]\n    step_metrics: list[float] = []\n    eval_samples: list[int] = []\n    failed = False\n\n    for step in range(1, steps + 1):\n        model.train()\n        idx = torch.randint(0, n, (batch_size,))\n        pred = model(train_x[idx])\n        loss = loss_fn(model, pred, train_y[idx])\n        if not torch.isfinite(loss):\n            failed = True\n            break\n        optimizer.zero_grad()\n        loss.backward()\n        optimizer.step()\n\n        metric = _test_mse(model, test_x, test_y)\n        if not math.isfinite(metric):\n            failed = True\n            break\n        eval_samples.append(step * batch_size)\n        step_metrics.append(metric)\n\n    final_metric = step_metrics[-1] if step_metrics else float(\"inf\")\n    if final_metric > fail_threshold:\n        failed = True\n\n    return {\n        \"failed\": failed,\n        \"final_test_mse\": final_metric,\n        \"eval_samples\": eval_samples,\n        \"step_metrics\": step_metrics,\n    }\n\n\ndef train(\n    train_x: torch.Tensor,\n    train_y: torch.Tensor,\n    *,\n    steps: int,\n    batch_size: int,\n    seed: int = 0,\n) -> None:\n    \"\"\"Minimal training entrypoint (no evaluation).\"\"\"\n    train_and_eval(\n        train_x,\n        train_y,\n        test_x=train_x,\n        test_y=train_y,\n        steps=steps,\n        batch_size=batch_size,\n        seed=seed,\n        fail_threshold=float(\"inf\"),\n    )\n",
